import{_ as a,e as t,g as n,o as l}from"./app-CiLORBRc.js";const s={};function h(r,e){return l(),t("div",null,e[0]||(e[0]=[n('<h2 id="个人陈述" tabindex="-1"><a class="header-anchor" href="#个人陈述"><span>个人陈述</span></a></h2><p>探索生命奥秘：从分子机制到人工智能的跨学科之旅 作为山东大学 2022 级生物科学专业本科生，我始终坚信生物医学研究的未来在于多学科交叉创新。通过系统的专业学习与科研实践，我逐步构建起从分子生物学到计算科学的知识体系，形成了以生物信息学为核心、结合人工智能与实验验证的研究方法论。以下从学术兴趣、研究成果与职业规划三方面阐述我的学术发展轨迹。</p><h2 id="一、学术兴趣的萌芽与深化" tabindex="-1"><a class="header-anchor" href="#一、学术兴趣的萌芽与深化"><span>一、学术兴趣的萌芽与深化</span></a></h2><p>我的科研启蒙始于对海洋微生物生态的探索。2023 年参与的 &quot;海洋微生物与环境互作机制研究&quot; 中，我通过 200 + 份海水样本分析，发现微生物丰度与碳含量的非线性关系，相关成果获国家级三等奖。这段经历使我深刻认识到数据驱动方法在生态学研究中的价值，也培养了我对生物大数据分析的敏感性。 随着学习深入，我将兴趣聚焦于肿瘤生物学与蛋白质工程。2024 年加入耶鲁大学陈教授团队，独立开展胰腺癌巨噬细胞单细胞图谱研究。通过整合 12,345 个单细胞数据，我开发了跨平台分析流程（SeuratV5+Harmony），首次发现 SLC11A1+CD163 + 巨噬细胞亚群作为潜在诊断标志物。该成果发表于 EI 期刊并被审稿人推荐为封面候选，印证了我在单细胞数据分析领域的创新能力。</p><h2 id="二、技术能力的构建与突破" tabindex="-1"><a class="header-anchor" href="#二、技术能力的构建与突破"><span>二、技术能力的构建与突破</span></a></h2><p>在计算生物学领域，我形成了 &quot;算法开发 - 数据整合 - 工程部署&quot; 的全流程能力： 算法创新：设计图神经网络模型（GCN+GAT）预测蛋白质互作，AUC-ROC 达 0.89，发现肺癌相关靶点 3 个；开发 YOLOv8 级联模型，实现细胞计数（95.2%）与 CT 肿瘤判别（AUC 0.92），检测效率提升 400%。 数据工程：构建多模态蛋白质互作数据库（STRING+PDB），采集 NCBI 数据库 2,347 条 HMTp210 序列建立血清型预测数据集。 工程化实践：通过 Docker 容器化部署生物信息学工具，开发交互式分析平台（Vue3+Three.js），代码获 GitHub 200 + 次 star，部署方案被 3 家医院采用。 在分子生物学领域，我掌握了从基因克隆到分子模拟的完整技术链： 完成 500ns Gromacs 动力学模拟，揭示糖基化对胶原蛋白热稳定性的影响（ΔTm=+4.2℃），相关成果发表于《JBC》。 设计 3 种突变体质粒验证羟化酶催化效率差异，结合 AlphaFold2 预测糖基化位点，开发预测工具准确率 89.7%。</p><h2 id="三、学术贡献的社会价值" tabindex="-1"><a class="header-anchor" href="#三、学术贡献的社会价值"><span>三、学术贡献的社会价值</span></a></h2><p>我始终关注研究成果的临床转化与产业应用： 开发的胰腺癌巨噬细胞标志物检测方案，已与齐鲁医院合作开展临床验证。 YOLOv8 影像分析平台通过 FastAPI 微服务架构，实现跨设备兼容，降低基层医院 AI 诊断门槛。 副鸡禽杆菌血清型预测模型（准确率 91%）被山东畜牧局采纳，用于优化疫苗研发策略。</p><h2 id="四、未来规划-从研究者到创新者" tabindex="-1"><a class="header-anchor" href="#四、未来规划-从研究者到创新者"><span>四、未来规划：从研究者到创新者</span></a></h2><p>短期目标是攻读生物信息学或计算生物学方向博士学位，深化机器学习在蛋白质组学与单细胞测序中的应用。计划开发更高效的多组学数据整合算法，解决肿瘤微环境异质性难题。 长期愿景是建立跨学科研究团队，推动人工智能与精准医学的深度融合。特别关注基于结构生物学的药物设计，希望通过蛋白质互作网络分析，发现更多具有临床价值的药物靶点。</p><h2 id="结语" tabindex="-1"><a class="header-anchor" href="#结语"><span>结语</span></a></h2><p>从海洋微生物到肿瘤细胞，从分子模拟到人工智能，我的科研之路始终围绕 &quot;理解生命本质、解决实际问题&quot; 展开。期待在贵校继续探索生物医学前沿，用数据科学的钥匙开启生命奥秘的新篇章。</p>',12)]))}const p=a(s,[["render",h],["__file","statement2.html.vue"]]),c=JSON.parse('{"path":"/zh/statement2.html","title":"","lang":"zh-CN","frontmatter":{},"headers":[{"level":2,"title":"个人陈述","slug":"个人陈述","link":"#个人陈述","children":[]},{"level":2,"title":"一、学术兴趣的萌芽与深化","slug":"一、学术兴趣的萌芽与深化","link":"#一、学术兴趣的萌芽与深化","children":[]},{"level":2,"title":"二、技术能力的构建与突破","slug":"二、技术能力的构建与突破","link":"#二、技术能力的构建与突破","children":[]},{"level":2,"title":"三、学术贡献的社会价值","slug":"三、学术贡献的社会价值","link":"#三、学术贡献的社会价值","children":[]},{"level":2,"title":"四、未来规划：从研究者到创新者","slug":"四、未来规划-从研究者到创新者","link":"#四、未来规划-从研究者到创新者","children":[]},{"level":2,"title":"结语","slug":"结语","link":"#结语","children":[]}],"git":{},"filePathRelative":"zh/statement2.md","excerpt":"<h2>个人陈述</h2>\\n<p>探索生命奥秘：从分子机制到人工智能的跨学科之旅\\n作为山东大学 2022 级生物科学专业本科生，我始终坚信生物医学研究的未来在于多学科交叉创新。通过系统的专业学习与科研实践，我逐步构建起从分子生物学到计算科学的知识体系，形成了以生物信息学为核心、结合人工智能与实验验证的研究方法论。以下从学术兴趣、研究成果与职业规划三方面阐述我的学术发展轨迹。</p>\\n<h2>一、学术兴趣的萌芽与深化</h2>\\n<p>我的科研启蒙始于对海洋微生物生态的探索。2023 年参与的 \\"海洋微生物与环境互作机制研究\\" 中，我通过 200 + 份海水样本分析，发现微生物丰度与碳含量的非线性关系，相关成果获国家级三等奖。这段经历使我深刻认识到数据驱动方法在生态学研究中的价值，也培养了我对生物大数据分析的敏感性。\\n随着学习深入，我将兴趣聚焦于肿瘤生物学与蛋白质工程。2024 年加入耶鲁大学陈教授团队，独立开展胰腺癌巨噬细胞单细胞图谱研究。通过整合 12,345 个单细胞数据，我开发了跨平台分析流程（SeuratV5+Harmony），首次发现 SLC11A1+CD163 + 巨噬细胞亚群作为潜在诊断标志物。该成果发表于 EI 期刊并被审稿人推荐为封面候选，印证了我在单细胞数据分析领域的创新能力。</p>"}');export{p as comp,c as data};
